(351, '3056', 'like_card', '{\"ar\": \"360 Moms Jordan\", \"en\": \"360 Moms Jordan\"}', '{\"ar\": \" About the AI Parents Advisor:Are you a parent with questions? We&apos;ve got answers!  Chat with AI Parents Advisor—your smart, friendly assistant for instant, science-backed tips on kids&apos; and women&apos;s health & well-being. Let’s make parenting easier together!\", \"en\": \" About the AI Parents Advisor:Are you a parent with questions? We&apos;ve got answers!  Chat with AI Parents Advisor—your smart, friendly assistant for instant, science-backed tips on kids&apos; and women&apos;s health & well-being. Let’s make parenting easier together!\"}', '{\"ar\": \"1-Go to this page   https://www.360moms.net2-Choose the plan that suits you: monthly or yearly.3-Click register to create an account4-Add your voucher code into the box allocated.5-Complete payment.Enjoy your subscription!\", \"en\": \"1-Go to this page   https://www.360moms.net2-Choose the plan that suits you: monthly or yearly.3-Click register to create an account4-Add your voucher code into the box allocated.5-Complete payment.Enjoy your subscription!\"}', '{\"ar\": \"- You can only use the e-voucher / gift card for one time..\", \"en\": \"- You can only use the e-voucher / gift card for one time..\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
