(394, '1131', 'like_card', '{\"ar\": \"Apple Gift Card - Turkey\", \"en\": \"Apple Gift Card - Turkey\"}', '{\"ar\": \"Get Apple Cards and enjoy apps, games, music, movies, TV shows, and more at: Apple Store, iBook Store, and Mac App Store.\", \"en\": \"Get Apple Cards and enjoy apps, games, music, movies, TV shows, and more at: Apple Store, iBook Store, and Mac App Store.\"}', '{\"ar\": \"How to redeem Apple store cards:1 - Enter your account information in the Apple Store.2- Enter the Redeem gift card or code.3- Enter the card code that you got from LikeCard.4- Click on Redeem.\", \"en\": \"How to redeem Apple store cards:1 - Enter your account information in the Apple Store.2- Enter the Redeem gift card or code.3- Enter the card code that you got from LikeCard.4- Click on Redeem.\"}', '{\"ar\": \"1- Valid only for Turkey transactions in Apple properties.\\\\n2- For assistance, visit: support.apple.com/giftcard\\\\n(Opens in a new window) or call 800-275-2273.\\\\n3- Not redeemable at Apple resellers or for cash, and no resale, refunds, or exchanges, except as required by law.\\\\n4- Apple is not responsible for unauthorized use. Terms apply; see: apple.com/us/go/legal/gc (Opens in a new window).\\\\n5- Issued by Apple Value Services, LLC (AVS). ©2023 Apple Inc. All rights reserved.\\\\n\", \"en\": \"1- Valid only for Turkey transactions in Apple properties.\\\\n2- For assistance, visit: support.apple.com/giftcard\\\\n(Opens in a new window) or call 800-275-2273.\\\\n3- Not redeemable at Apple resellers or for cash, and no resale, refunds, or exchanges, except as required by law.\\\\n4- Apple is not responsible for unauthorized use. Terms apply; see: apple.com/us/go/legal/gc (Opens in a new window).\\\\n5- Issued by Apple Value Services, LLC (AVS). ©2023 Apple Inc. All rights reserved.\\\\n\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
