(398, '1917', 'like_card', '{\"ar\": \"Huawei App Gallery - Egypt\", \"en\": \"Huawei App Gallery - Egypt\"}', '{\"ar\": \"HUAWEI Points are a virtual currency sold and managed by Huawei. HUAWEI Points can be used to purchase virtual offerings and value-added services in Huawei apps.HUAWEI Points can be used for in-app purchases in Huawei apps, such as Cloud, AppGallery, HUAWEI Video, Music, Themes, and GameCenter.If the HUAWEI Points option is not displayed on the Huawei In-App Purchases screen, the app does not support HUAWEI Points.\", \"en\": \"HUAWEI Points are a virtual currency sold and managed by Huawei. HUAWEI Points can be used to purchase virtual offerings and value-added services in Huawei apps.HUAWEI Points can be used for in-app purchases in Huawei apps, such as Cloud, AppGallery, HUAWEI Video, Music, Themes, and GameCenter.If the HUAWEI Points option is not displayed on the Huawei In-App Purchases screen, the app does not support HUAWEI Points.\"}', '{\"ar\": \"How to redeem Huawei card:\\\\n1- Go to Huawei&apos;s website or open the Huawei app on your device.\\\\n2- Sign in to your account.\\\\n3- Access the \\\"Gift Card\\\" section: Look for the \\\"Gift Card\\\" or \\\"Redeem\\\" section on the website or app. It is usually located in the account settings or payment options.\\\\n4- Enter the Gift Card code and click Redeem.\", \"en\": \"How to redeem Huawei card:\\\\n1- Go to Huawei&apos;s website or open the Huawei app on your device.\\\\n2- Sign in to your account.\\\\n3- Access the \\\"Gift Card\\\" section: Look for the \\\"Gift Card\\\" or \\\"Redeem\\\" section on the website or app. It is usually located in the account settings or payment options.\\\\n4- Enter the Gift Card code and click Redeem.\"}', '{\"ar\": \"If the HUAWEI Points option is not displayed on the Huawei In-App Purchases screen, the app does not support HUAWEI Points.\", \"en\": \"If the HUAWEI Points option is not displayed on the Huawei In-App Purchases screen, the app does not support HUAWEI Points.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(399, '1759', 'like_card', '{\"ar\": \"Huawei App Gallery - KSA\", \"en\": \"Huawei App Gallery - KSA\"}', '{\"ar\": \"HUAWEI Points are a virtual currency sold and managed by Huawei. HUAWEI Points can be used to purchase virtual offerings and value-added services in Huawei apps.HUAWEI Points can be used for in-app purchases in Huawei apps, such as Cloud, AppGallery, HUAWEI Video, Music, Themes, and GameCenter.If the HUAWEI Points option is not displayed on the Huawei In-App Purchases screen, the app does not support HUAWEI Points.\", \"en\": \"HUAWEI Points are a virtual currency sold and managed by Huawei. HUAWEI Points can be used to purchase virtual offerings and value-added services in Huawei apps.HUAWEI Points can be used for in-app purchases in Huawei apps, such as Cloud, AppGallery, HUAWEI Video, Music, Themes, and GameCenter.If the HUAWEI Points option is not displayed on the Huawei In-App Purchases screen, the app does not support HUAWEI Points.\"}', '{\"ar\": \"1- Purchase a Huawei Gift Card through the available channels.2- Log in to your Huawei account on the AppGallery.3- From the “Me” page, tap on “Huawei Account,” then select “Payment and Purchases” and click on “Huawei Points.”4- Tap on “Redeem,” then enter the code manually or scan it to complete the top-up successfully.5- The additional 20% bonus will be added directly to your Huawei Points balance.6- Use your points for your next purchase within games and apps (except for the game Top War).7- The offer is valid only in the United Arab Emirates and Saudi Arabia.8- To receive the 20% bonus successfully, make sure you have the latest AppGallery version (12.3.0.616) and that HMS Core is properly installed.9- One (1) Huawei Point equals one (1) AED/SAR.10- You will receive a notification once the points are successfully credited.\", \"en\": \"1- Purchase a Huawei Gift Card through the available channels.2- Log in to your Huawei account on the AppGallery.3- From the “Me” page, tap on “Huawei Account,” then select “Payment and Purchases” and click on “Huawei Points.”4- Tap on “Redeem,” then enter the code manually or scan it to complete the top-up successfully.5- The additional 20% bonus will be added directly to your Huawei Points balance.6- Use your points for your next purchase within games and apps (except for the game Top War).7- The offer is valid only in the United Arab Emirates and Saudi Arabia.8- To receive the 20% bonus successfully, make sure you have the latest AppGallery version (12.3.0.616) and that HMS Core is properly installed.9- One (1) Huawei Point equals one (1) AED/SAR.10- You will receive a notification once the points are successfully credited.\"}', '{\"ar\": \"If the HUAWEI Points option is not displayed on the Huawei In-App Purchases screen, the app does not support HUAWEI Points.\", \"en\": \"If the HUAWEI Points option is not displayed on the Huawei In-App Purchases screen, the app does not support HUAWEI Points.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
