(422, '3093', 'like_card', '{\"ar\": \"PUBG\", \"en\": \"PUBG\"}', '{\"ar\": \"To the action and excitement lovers who are fighting for survival in Pubg Mobile, you can now charge the skins of PUBG, to get more suspense and fun and fly in a world of limitless imagination!  Recharge PUBG now, get PUBG points or PUBG widgets, and enjoy buying everything you want to acquire from additional special features within the game.  Charge PUBG uc wedges now and acquire unique PUBG game weapons, which enable you to achieve a crushing victory over your enemies, and you can also acquire different clothes with wonderful colors in the game that distinguish you among your colleagues.\", \"en\": \"To the action and excitement lovers who are fighting for survival in Pubg Mobile, you can now charge the skins of PUBG, to get more suspense and fun and fly in a world of limitless imagination!  Recharge PUBG now, get PUBG points or PUBG widgets, and enjoy buying everything you want to acquire from additional special features within the game.  Charge PUBG uc wedges now and acquire unique PUBG game weapons, which enable you to achieve a crushing victory over your enemies, and you can also acquire different clothes with wonderful colors in the game that distinguish you among your colleagues.\"}', '{\"ar\": \"How to redeem Pubg uc cards?\\\\n1- Visit ( https:// midasbuy.com/midasbuy/tr/redeem/pubgm)\\\\n2- Enter your PUBG Mobile operator ID.\\\\n3- Enter the code, then click OK to redeem.\\\\n4- You will receive UC in your PUBG account immediately after redemption.\\\\nNote: This product does not apply to Chinese/Japanese/Korean/Taiwanese/Vietnamese PUBG servers.\\\\nLearn how to create a midasbuy account:\\\\n(https://like4card.com/Midasbuy-Account.html)\", \"en\": \"How to redeem Pubg uc cards?\\\\n1- Visit ( https:// midasbuy.com/midasbuy/tr/redeem/pubgm)\\\\n2- Enter your PUBG Mobile operator ID.\\\\n3- Enter the code, then click OK to redeem.\\\\n4- You will receive UC in your PUBG account immediately after redemption.\\\\nNote: This product does not apply to Chinese/Japanese/Korean/Taiwanese/Vietnamese PUBG servers.\\\\nLearn how to create a midasbuy account:\\\\n(https://like4card.com/Midasbuy-Account.html)\"}', '{\"ar\": \"- This product is for the global PUBG version.\", \"en\": \"- This product is for the global PUBG version.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(423, '3059', 'like_card', '{\"ar\": \"PUBG - Top Up\", \"en\": \"PUBG - Top Up\"}', '{\"ar\": \"Get PUBG UC and enjoy many great features in the in-game store like Lucky Spin and Season pass.\", \"en\": \"Get PUBG UC and enjoy many great features in the in-game store like Lucky Spin and Season pass.\"}', '{\"ar\": \"How do I top up my PUBG Mobile account? \\\\n1- Select Direct PUBG Mobile Top-up. 2- Enter your Player ID. 3- Add your purchase amount.\", \"en\": \"How do I top up my PUBG Mobile account? \\\\n1- Select Direct PUBG Mobile Top-up. 2- Enter your Player ID. 3- Add your purchase amount.\"}', '{\"ar\": \"This product is for the global PUBG version\", \"en\": \"This product is for the global PUBG version\"}', 422, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(424, '201', 'like_card', '{\"ar\": \"PUBG\", \"en\": \"PUBG\"}', '{\"ar\": \"To the action and excitement lovers who are fighting for survival in Pubg Mobile, you can now charge the skins of PUBG, to get more suspense and fun and fly in a world of limitless imagination!  \\\\nRecharge PUBG now, get PUBG points or PUBG widgets, and enjoy buying everything you want to acquire from additional special features within the game.  \\\\nCharge PUBG uc wedges now and acquire unique PUBG game weapons, which enable you to achieve a crushing victory over your enemies, and you can also acquire different clothes with wonderful colors in the game that distinguish you among your colleagues.\\\\n\", \"en\": \"To the action and excitement lovers who are fighting for survival in Pubg Mobile, you can now charge the skins of PUBG, to get more suspense and fun and fly in a world of limitless imagination!  \\\\nRecharge PUBG now, get PUBG points or PUBG widgets, and enjoy buying everything you want to acquire from additional special features within the game.  \\\\nCharge PUBG uc wedges now and acquire unique PUBG game weapons, which enable you to achieve a crushing victory over your enemies, and you can also acquire different clothes with wonderful colors in the game that distinguish you among your colleagues.\\\\n\"}', '{\"ar\": \"How to redeem Pubg uc cards?\\\\n1- Visit ( https:// midasbuy.com/midasbuy/tr/redeem/pubgm)\\\\n2- Enter your PUBG Mobile operator ID.\\\\n3- Enter the code, then click OK to redeem.\\\\n4- You will receive UC in your PUBG account immediately after redemption.\\\\nNote: This product does not apply to Chinese/Japanese/Korean/Taiwanese/Vietnamese PUBG servers.\\\\nLearn how to create a midasbuy account:\\\\n(https://like4card.com/Midasbuy-Account.html)\", \"en\": \"How to redeem Pubg uc cards?\\\\n1- Visit ( https:// midasbuy.com/midasbuy/tr/redeem/pubgm)\\\\n2- Enter your PUBG Mobile operator ID.\\\\n3- Enter the code, then click OK to redeem.\\\\n4- You will receive UC in your PUBG account immediately after redemption.\\\\nNote: This product does not apply to Chinese/Japanese/Korean/Taiwanese/Vietnamese PUBG servers.\\\\nLearn how to create a midasbuy account:\\\\n(https://like4card.com/Midasbuy-Account.html)\"}', '{\"ar\": \"- This product is for the global PUBG version.\", \"en\": \"- This product is for the global PUBG version.\"}', 422, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(425, '1223', 'like_card', '{\"ar\": \"Dooms Days\", \"en\": \"Dooms Days\"}', '{\"ar\": \"Doomsday: Last Survivors is a zombie survival game with multiplayer online competition and real-time strategy elements. Set in a near future where zombies have taken over the world, survivors must fight for their lives and humanity&apos;s future. As the Commander, you must lead fellow survivors to build their Shelter, explore fog-filled areas, and fight the zombies and rival factions! Are you tired of the usual strategy games and love zombie games? Check out Doomsday: Last Survivors to experience the exciting survival game!\", \"en\": \"Doomsday: Last Survivors is a zombie survival game with multiplayer online competition and real-time strategy elements. Set in a near future where zombies have taken over the world, survivors must fight for their lives and humanity&apos;s future. As the Commander, you must lead fellow survivors to build their Shelter, explore fog-filled areas, and fight the zombies and rival factions! Are you tired of the usual strategy games and love zombie games? Check out Doomsday: Last Survivors to experience the exciting survival game!\"}', '{\"ar\": \"How to redeem Dooms Days card:1- Tap your portrait on the top left corner of the game interface.2- Go to Settings.3- Tap Gift Code to enter the CODE and redeem.\", \"en\": \"How to redeem Dooms Days card:1- Tap your portrait on the top left corner of the game interface.2- Go to Settings.3- Tap Gift Code to enter the CODE and redeem.\"}', '{\"ar\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\", \"en\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(426, '777', 'like_card', '{\"ar\": \"PUBG New State\", \"en\": \"PUBG New State\"}', '{\"ar\": \"PUBG new State code cards\\\\n- For PUBG fans and players, from the Battle ground, we are offering you today PUBG NEW STATE recharge cards, to charge your account and get access to everything you need from lethal weapons, cool costumes, and modern tugs to look better and perform stronger.\\\\n- With PUBG New State charging cards, one step separates you from elegance.\\\\n- Order your card, get the code and buy various outfits and powerful weapons to enjoy new stages in PUBG new state.\\\\n- It comes with different prices and packages to suit everyone&apos;s need, with completely secure payment methods.\\\\n- You receive the code immediately after purchase, to crush your enemies and win. \\\\n- PUBG New State Cards, because it&apos;s more than a game and because you deserve the best.\\\\n\", \"en\": \"PUBG new State code cards\\\\n- For PUBG fans and players, from the Battle ground, we are offering you today PUBG NEW STATE recharge cards, to charge your account and get access to everything you need from lethal weapons, cool costumes, and modern tugs to look better and perform stronger.\\\\n- With PUBG New State charging cards, one step separates you from elegance.\\\\n- Order your card, get the code and buy various outfits and powerful weapons to enjoy new stages in PUBG new state.\\\\n- It comes with different prices and packages to suit everyone&apos;s need, with completely secure payment methods.\\\\n- You receive the code immediately after purchase, to crush your enemies and win. \\\\n- PUBG New State Cards, because it&apos;s more than a game and because you deserve the best.\\\\n\"}', '{\"ar\": \"How to redeem PUBG NEW STATE cards:\\\\n1- Go to the following link from ( https://newstate.pubg.com/en/redemption )\\\\n2- Add the code you got.\\\\n3- Add your player ID, then click Redeem.\\\\n4- After that, go to the message box to receive in-game balance.\\\\n\", \"en\": \"How to redeem PUBG NEW STATE cards:\\\\n1- Go to the following link from ( https://newstate.pubg.com/en/redemption )\\\\n2- Add the code you got.\\\\n3- Add your player ID, then click Redeem.\\\\n4- After that, go to the message box to receive in-game balance.\\\\n\"}', '{\"ar\": \"- This product is valid for use in all countries.\", \"en\": \"- This product is valid for use in all countries.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(427, '1430', 'like_card', '{\"ar\": \"Castle Clash\", \"en\": \"Castle Clash\"}', '{\"ar\": \"A new chapter begins in Narcia in the Forsaken Land. Join Clashers from around the world in this new challenge! Battle against powerful rivals, showcase your skills, and upgrade your Heroes from scratch. Only by mastering upgrade strategies and battle tactics can you defeat bosses and achieve ultimate victory! A new dragon, Malefica, has also descended upon Narcia. Join forces and embark on a new adventure together!\", \"en\": \"A new chapter begins in Narcia in the Forsaken Land. Join Clashers from around the world in this new challenge! Battle against powerful rivals, showcase your skills, and upgrade your Heroes from scratch. Only by mastering upgrade strategies and battle tactics can you defeat bosses and achieve ultimate victory! A new dragon, Malefica, has also descended upon Narcia. Join forces and embark on a new adventure together!\"}', '{\"ar\": \"How to redeem Castle Clash card:\\\\n1- Go to Settings by tapping the gear icon on the bottom left corner of the main interface.\\\\n2- Go to the Account tab to see a gift box icon.\\\\n3- Tap the gift box icon and enter the code to redeem your gift.\\\\nHow to find your IGG ID:\\\\nGo to Settings by tapping the gear icon on the bottom left corner of the main interface. Go to the Account tab to view your IGG ID.\\\\n\", \"en\": \"How to redeem Castle Clash card:\\\\n1- Go to Settings by tapping the gear icon on the bottom left corner of the main interface.\\\\n2- Go to the Account tab to see a gift box icon.\\\\n3- Tap the gift box icon and enter the code to redeem your gift.\\\\nHow to find your IGG ID:\\\\nGo to Settings by tapping the gear icon on the bottom left corner of the main interface. Go to the Account tab to view your IGG ID.\\\\n\"}', '{\"ar\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded. \", \"en\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded. \"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(428, '1138', 'like_card', '{\"ar\": \"Knives out\", \"en\": \"Knives out\"}', '{\"ar\": \"Dive into a breathtaking survival adventure in Knives Out!\\\\nFly! To anywhere you want with a very large map of more than 100 players.\\\\nExplore how to survive in the Knives Out battleground.\\\\nMeet new friends in this survival journey.\\\\nHave fun playing have fun making a team.\", \"en\": \"Dive into a breathtaking survival adventure in Knives Out!\\\\nFly! To anywhere you want with a very large map of more than 100 players.\\\\nExplore how to survive in the Knives Out battleground.\\\\nMeet new friends in this survival journey.\\\\nHave fun playing have fun making a team.\"}', '{\"ar\": \"How to redeem Knives Out card:\\\\n1- Enter the link: https://pay.neteasegames.com/\\\\n2- Select your game server.\\\\n3- Enter your ID.\\\\n4- Enter the code and select the “Continue” button.\\\\n5- Enter your serial number (Redeem code).\\\\n6- Enter the “Activate” button.\\\\n\", \"en\": \"How to redeem Knives Out card:\\\\n1- Enter the link: https://pay.neteasegames.com/\\\\n2- Select your game server.\\\\n3- Enter your ID.\\\\n4- Enter the code and select the “Continue” button.\\\\n5- Enter your serial number (Redeem code).\\\\n6- Enter the “Activate” button.\\\\n\"}', '{\"ar\": \"1- Valid for 10 years.\\\\n2- Is redeemable for the following Games (identity V, Life After, The Lord of the Rings: Rise to War, Knives Out).\\\\n3- Once purchased, cannot be returned or refunded.\\\\n\", \"en\": \"1- Valid for 10 years.\\\\n2- Is redeemable for the following Games (identity V, Life After, The Lord of the Rings: Rise to War, Knives Out).\\\\n3- Once purchased, cannot be returned or refunded.\\\\n\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(429, '1267', 'like_card', '{\"ar\": \"Travian Legends\", \"en\": \"Travian Legends\"}', '{\"ar\": \"Travian Legends, released in 2004, is a browser-based MMORTS game.\\\\nTravian Gold is the in-game currency used. You can shop in the Travian marketplace with gold and become an unstoppable warrior.\\\\n\", \"en\": \"Travian Legends, released in 2004, is a browser-based MMORTS game.\\\\nTravian Gold is the in-game currency used. You can shop in the Travian marketplace with gold and become an unstoppable warrior.\\\\n\"}', '{\"ar\": \"How to redeem Travian Legends card:\\\\n1- Log in to the game at www.travian.com/tr Then click on the gold icon.\\\\n2- Click on the \\\"Voucher\\\" button.\\\\n3- On the page that opens, enter the code you purchased from LikeCard and click on the \\\"Verify Voucher\\\" button.\\\\n\", \"en\": \"How to redeem Travian Legends card:\\\\n1- Log in to the game at www.travian.com/tr Then click on the gold icon.\\\\n2- Click on the \\\"Voucher\\\" button.\\\\n3- On the page that opens, enter the code you purchased from LikeCard and click on the \\\"Verify Voucher\\\" button.\\\\n\"}', '{\"ar\": \"1- It is a global product, EUR2- Regional Servers/Global: International, Europe, Asia, America, Arabics.\\\\n2- Products are delivered instantly via e-pin after the payment process is completed.\\\\n3- For digital products, product returns cannot be made in accordance with the relevant article of the Turkish Commercial Code.\\\\n\", \"en\": \"1- It is a global product, EUR2- Regional Servers/Global: International, Europe, Asia, America, Arabics.\\\\n2- Products are delivered instantly via e-pin after the payment process is completed.\\\\n3- For digital products, product returns cannot be made in accordance with the relevant article of the Turkish Commercial Code.\\\\n\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(430, '1758', 'like_card', '{\"ar\": \"Malooba\", \"en\": \"Malooba\"}', '{\"ar\": \"Malooba Ludo 3D – The Ultimate Ludo Experience!Enjoy an unprecedented 3D Ludo experience with stunning designs, voice chat, and fun emojis and gifts! Play, compete, and chat like never before! Play, Compete & Chat!Challenge your friends and family in Ludo with high-quality 3D graphics and exciting new game modes that make the experience more fun and competitive.\", \"en\": \"Malooba Ludo 3D – The Ultimate Ludo Experience!Enjoy an unprecedented 3D Ludo experience with stunning designs, voice chat, and fun emojis and gifts! Play, compete, and chat like never before! Play, Compete & Chat!Challenge your friends and family in Ludo with high-quality 3D graphics and exciting new game modes that make the experience more fun and competitive.\"}', '{\"ar\": \"1- Click on your profile page. 2- Copy your account ID by clicking the copy button, then go to the following link to activate the voucher: Click here 3- Enter your ID in the first field \\\"Enter Your Account ID\\\".4- Enter your voucher code in the second field \\\"Enter Voucher Code\\\".5- Click on the \\\"Redeem\\\" button to receive the value of the voucher you own\", \"en\": \"1- Click on your profile page. 2- Copy your account ID by clicking the copy button, then go to the following link to activate the voucher: Click here 3- Enter your ID in the first field \\\"Enter Your Account ID\\\".4- Enter your voucher code in the second field \\\"Enter Voucher Code\\\".5- Click on the \\\"Redeem\\\" button to receive the value of the voucher you own\"}', '{\"ar\": \"- Some vouchers have an expiration date, and you must activate them before they expire.\", \"en\": \"- Some vouchers have an expiration date, and you must activate them before they expire.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(431, '1231', 'like_card', '{\"ar\": \"Heroes Evolved\", \"en\": \"Heroes Evolved\"}', '{\"ar\": \"Heroes Evolved - a free global strategy and action game where you will be a part of a 5-member team aiming at destroying the enemy base! This is a really fun MOBA in which there are 100+ unique heroes for you to choose to battle against real rivals from all over the world. You can make the most of your skills, teamwork, intelligence and strategy to survive and succeed in the game.\\\\n\", \"en\": \"Heroes Evolved - a free global strategy and action game where you will be a part of a 5-member team aiming at destroying the enemy base! This is a really fun MOBA in which there are 100+ unique heroes for you to choose to battle against real rivals from all over the world. You can make the most of your skills, teamwork, intelligence and strategy to survive and succeed in the game.\\\\n\"}', '{\"ar\": \"How to redeem Heroes Evolved card:\\\\n1- Enter the link: https://topup.skarla.com/\\\\n2- Enter your Player Tag.\\\\n3- Enter your Voucher code.\\\\n4- Click on REDEEM.\\\\n\", \"en\": \"How to redeem Heroes Evolved card:\\\\n1- Enter the link: https://topup.skarla.com/\\\\n2- Enter your Player Tag.\\\\n3- Enter your Voucher code.\\\\n4- Click on REDEEM.\\\\n\"}', '{\"ar\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\", \"en\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(432, '1249', 'like_card', '{\"ar\": \"Badlanders\", \"en\": \"Badlanders\"}', '{\"ar\": \"Badlanders is a competitive survival looter shooter mobile game. Here, some become rich overnight while others lose it all.\", \"en\": \"Badlanders is a competitive survival looter shooter mobile game. Here, some become rich overnight while others lose it all.\"}', '{\"ar\": \"How to redeem Badlanders cards:1- Enter the link:pay.neteasegames.com2- Select your game server.3- Enter your ID.4- Enter the code and select the  Continue  button.5- Enter your serial number (Redeem code).6- Enter the  Activate  button.\", \"en\": \"How to redeem Badlanders cards:1- Enter the link:pay.neteasegames.com2- Select your game server.3- Enter your ID.4- Enter the code and select the  Continue  button.5- Enter your serial number (Redeem code).6- Enter the  Activate  button.\"}', '{\"ar\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\", \"en\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(433, '1270', 'like_card', '{\"ar\": \"Silkroad Gamegami - TR\", \"en\": \"Silkroad Gamegami - TR\"}', '{\"ar\": \"Silkroad Online is an MMORPG game that takes players on a journey through ancient Chinese, Islamic, and European civilizations. Since its first release, Silkroad Online has hosted over 250 million players.\\\\n\", \"en\": \"Silkroad Online is an MMORPG game that takes players on a journey through ancient Chinese, Islamic, and European civilizations. Since its first release, Silkroad Online has hosted over 250 million players.\\\\n\"}', '{\"ar\": \"How to redeem Silkroad card:\\\\n\\\\n1- Enter the link: Silkroad.gamegami.com\\\\n2- Open your account by logging in. If you don&apos;t have a membership, you can create an account from the \\\"Registration\\\" section.\\\\n3-Click on \\\"Install \\\" or \\\"Buy.\\\"\\\\n4- On the page that opens, enter the Silkroad Online Turkey Silk E-Pin code you purchased in the designated field on the screen and click the \\\"Install\\\" button.\\\\n\", \"en\": \"How to redeem Silkroad card:\\\\n\\\\n1- Enter the link: Silkroad.gamegami.com\\\\n2- Open your account by logging in. If you don&apos;t have a membership, you can create an account from the \\\"Registration\\\" section.\\\\n3-Click on \\\"Install \\\" or \\\"Buy.\\\"\\\\n4- On the page that opens, enter the Silkroad Online Turkey Silk E-Pin code you purchased in the designated field on the screen and click the \\\"Install\\\" button.\\\\n\"}', '{\"ar\": \"1- Silkroad Online Turkey Silk Codes are valid only in the Turkey region.\\\\n2- Products are delivered instantly via the electronic secret code after completing the payment.\\\\n3- For digital products, the product cannot be returned according to the relevant article of the Turkish Commercial Code.\\\\n\", \"en\": \"1- Silkroad Online Turkey Silk Codes are valid only in the Turkey region.\\\\n2- Products are delivered instantly via the electronic secret code after completing the payment.\\\\n3- For digital products, the product cannot be returned according to the relevant article of the Turkish Commercial Code.\\\\n\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(434, '1153', 'like_card', '{\"ar\": \"Infinite Lagrange\", \"en\": \"Infinite Lagrange\"}', '{\"ar\": \"You can use Infinity Lagrange Chu Coins products on the PC version.Purchase Infinity Lagrange Chu Coins and access many special items in the game.\", \"en\": \"You can use Infinity Lagrange Chu Coins products on the PC version.Purchase Infinity Lagrange Chu Coins and access many special items in the game.\"}', '{\"ar\": \"If you don’t know how to use and redeem codes? It’s pretty simple you just need to follow a few simple steps.Step 1: Open the GameStep 2: Now GO to the Settings option.Step 3: Click on the “Redemption Code”Step 4: Enter the Code and click Collect.\", \"en\": \"If you don’t know how to use and redeem codes? It’s pretty simple you just need to follow a few simple steps.Step 1: Open the GameStep 2: Now GO to the Settings option.Step 3: Click on the “Redemption Code”Step 4: Enter the Code and click Collect.\"}', '{\"ar\": \"This gift card is non-refundable and cannot be exchanged for cash.This gift card cannot be reloaded.\", \"en\": \"This gift card is non-refundable and cannot be exchanged for cash.This gift card cannot be reloaded.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(435, '375', 'like_card', '{\"ar\": \"Blizzard\", \"en\": \"Blizzard\"}', '{\"ar\": \"You have a passion for games? And you want to have a lot of fun?\\\\nThen don&apos;t miss out the benefits and privileges in blizzard entertainment store.\\\\nToday we offer you Blizzard pre-charging gift cards, so you can buy the best and newest games to\\\\nplay and enjoy with your friends.\\\\nNot only that, you also get an exclusive features and offers on blizzard entertainment store.\\\\nCall of Duty, World of Warcraft and many games with an excellent service are just one click away.\\\\nGet your blizzard gift card within a safe Payment method, charge your account and enjoy your favorite games.\\\\nCards with a variety of values and multiple prices to suit everyone&apos;s needs for an endless fun.\\\\nSo what are you waiting for?, get your gift card now and join the club for fun.\", \"en\": \"You have a passion for games? And you want to have a lot of fun?\\\\nThen don&apos;t miss out the benefits and privileges in blizzard entertainment store.\\\\nToday we offer you Blizzard pre-charging gift cards, so you can buy the best and newest games to\\\\nplay and enjoy with your friends.\\\\nNot only that, you also get an exclusive features and offers on blizzard entertainment store.\\\\nCall of Duty, World of Warcraft and many games with an excellent service are just one click away.\\\\nGet your blizzard gift card within a safe Payment method, charge your account and enjoy your favorite games.\\\\nCards with a variety of values and multiple prices to suit everyone&apos;s needs for an endless fun.\\\\nSo what are you waiting for?, get your gift card now and join the club for fun.\"}', '{\"ar\": \"How to redeem blizzard card:\\\\n1- Go to the link and log into your Blizzard account\\\\naccount.blizzard.com/overview\\\\n2- Enter the Account overview page\\\\n3- Add the card code and click on Redeem code\\\\n\", \"en\": \"How to redeem blizzard card:\\\\n1- Go to the link and log into your Blizzard account\\\\naccount.blizzard.com/overview\\\\n2- Enter the Account overview page\\\\n3- Add the card code and click on Redeem code\\\\n\"}', '{\"ar\": \"Select the card based on the account type.\", \"en\": \"Select the card based on the account type.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
