(445, '1280', 'like_card', '{\"ar\": \"Amazon - TR\", \"en\": \"Amazon - TR\"}', '{\"ar\": \"Amazon gift Cards:Amazon is one of the largest online shopping sites in the world.And for a better shopping experience at Amazon, now there is Amazon - TR gift cards.Amazon prepaid cards are shopping cards that enable you to make an integrated and excellent online shopping experience. You can buy whatever you need, without worrying about high interest or late fees, unlike credit cards.It is also an ideal gift for your family members or friends.Whether you are looking for clothes, perfumes, books or electronic devices, Amazon is your destination.All you have to do is open an account on Amazon store, order a card, and charge your account to start the journey of shopping on Amazon.\", \"en\": \"Amazon gift Cards:Amazon is one of the largest online shopping sites in the world.And for a better shopping experience at Amazon, now there is Amazon - TR gift cards.Amazon prepaid cards are shopping cards that enable you to make an integrated and excellent online shopping experience. You can buy whatever you need, without worrying about high interest or late fees, unlike credit cards.It is also an ideal gift for your family members or friends.Whether you are looking for clothes, perfumes, books or electronic devices, Amazon is your destination.All you have to do is open an account on Amazon store, order a card, and charge your account to start the journey of shopping on Amazon.\"}', '{\"ar\": \"How to redeem amazon card:\\\\n1- Go to Amazon.com.tr\\\\n2- Press the menu button.\\\\n3- Log in to your account.\\\\n4- Click on Manage Gift Cards Balance.\\\\n5- Choose to pay with gift cards.\\\\n6- Enter the card code that you got.\\\\n7- Click on apply to your balance.\", \"en\": \"How to redeem amazon card:\\\\n1- Go to Amazon.com.tr\\\\n2- Press the menu button.\\\\n3- Log in to your account.\\\\n4- Click on Manage Gift Cards Balance.\\\\n5- Choose to pay with gift cards.\\\\n6- Enter the card code that you got.\\\\n7- Click on apply to your balance.\"}', '{\"ar\": \"This product is for Turkey amazon accounts.\", \"en\": \"This product is for Turkey amazon accounts.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(446, '72', 'like_card', '{\"ar\": \"Amazon - USA\", \"en\": \"Amazon - USA\"}', '{\"ar\": \"Amazon gift Cards:Amazon is one of the largest online shopping sites in the world.And for a better shopping experience at Amazon, now there is Amazon gift cards.Amazon prepaid cards are shopping cards that enable you to make an integrated and excellent online shopping experience. You can buy whatever you need, without worrying about high interest or late fees, unlike credit cards.It is also an ideal gift for your family members or friends.Whether you are looking for clothes, perfumes, books or electronic devices, Amazon is your destination.All you have to do is open an account on Amazon store, order a card, and charge your account to start the journey of shopping on Amazon.\\\\n\", \"en\": \"Amazon gift Cards:Amazon is one of the largest online shopping sites in the world.And for a better shopping experience at Amazon, now there is Amazon gift cards.Amazon prepaid cards are shopping cards that enable you to make an integrated and excellent online shopping experience. You can buy whatever you need, without worrying about high interest or late fees, unlike credit cards.It is also an ideal gift for your family members or friends.Whether you are looking for clothes, perfumes, books or electronic devices, Amazon is your destination.All you have to do is open an account on Amazon store, order a card, and charge your account to start the journey of shopping on Amazon.\\\\n\"}', '{\"ar\": \"How to redeem amazon card:\\\\n1- Go to Amazon.com\\\\n2- Press the menu button.\\\\n3- Log in to your account.\\\\n4- Click on Manage Gift Cards Balance.\\\\n5- Choose to pay with gift cards.\\\\n6- Enter the card code that you got.\\\\n7- Click on apply to your balance.\\\\n\", \"en\": \"How to redeem amazon card:\\\\n1- Go to Amazon.com\\\\n2- Press the menu button.\\\\n3- Log in to your account.\\\\n4- Click on Manage Gift Cards Balance.\\\\n5- Choose to pay with gift cards.\\\\n6- Enter the card code that you got.\\\\n7- Click on apply to your balance.\\\\n\"}', '{\"ar\": \"1- This card is intended exclusively for American accounts, and therefore your account must be American so that you do not encounter any problems when trying to charge or use the card.\\\\n2- Any violation of Amazon&apos;s policy may result in your account being banned.\\\\n3- Please see the terms and conditions from the link Use Amazon Cards before using the card: https://www.amazon.com/gp/help/customer/display.html?nodeId=201937200\\\\n\", \"en\": \"1- This card is intended exclusively for American accounts, and therefore your account must be American so that you do not encounter any problems when trying to charge or use the card.\\\\n2- Any violation of Amazon&apos;s policy may result in your account being banned.\\\\n3- Please see the terms and conditions from the link Use Amazon Cards before using the card: https://www.amazon.com/gp/help/customer/display.html?nodeId=201937200\\\\n\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
