(462, '373', 'like_card', '{\"ar\": \"Hulu+\", \"en\": \"Hulu+\"}', '{\"ar\": \"Hulu is the best way to watch your favorite TV shows, all ad-free! From drama to comedy, watch the latest episodes of your favorite TV shows live and without ads. Watch from anywhere on your phone, tablet, or other connected devices.\\\\n\", \"en\": \"Hulu is the best way to watch your favorite TV shows, all ad-free! From drama to comedy, watch the latest episodes of your favorite TV shows live and without ads. Watch from anywhere on your phone, tablet, or other connected devices.\\\\n\"}', '{\"ar\": \"How to redeem Hulu+ cards:\\\\n\\\\n\\\\n1- Enter the following link: https://secure.hulu.com/start/gifting\\\\n2- Enter the card code that you got.\\\\n3- Click on Redeem.\\\\n\", \"en\": \"How to redeem Hulu+ cards:\\\\n\\\\n\\\\n1- Enter the following link: https://secure.hulu.com/start/gifting\\\\n2- Enter the card code that you got.\\\\n3- Click on Redeem.\\\\n\"}', '{\"ar\": \"1- When the gift balance is spent, access to Hulu will expire unless you provide another payment method, in which case the monthly subscription fee will apply until you cancel. The remaining gift balance will be forfeited upon cancellation.\\\\n2- It may not be exchanged or used to offset amounts owed to Hulu. It cannot be resold, non-refundable or redeemable for cash, unless required by law.\\\\n3- Hulu is not responsible for lost or stolen gift cards or codes.\\\\n4- Visit www.hulu.com/start/gifting_terms for full terms and conditions.\", \"en\": \"1- When the gift balance is spent, access to Hulu will expire unless you provide another payment method, in which case the monthly subscription fee will apply until you cancel. The remaining gift balance will be forfeited upon cancellation.\\\\n2- It may not be exchanged or used to offset amounts owed to Hulu. It cannot be resold, non-refundable or redeemable for cash, unless required by law.\\\\n3- Hulu is not responsible for lost or stolen gift cards or codes.\\\\n4- Visit www.hulu.com/start/gifting_terms for full terms and conditions.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(463, '1467', 'like_card', '{\"ar\": \"WATCH IT\", \"en\": \"WATCH IT\"}', '{\"ar\": \"WATCH IT, the premier VOD platform in the region, has the biggest Arabic library in the MENA region, from original productions, to exclusives including series, programs, movies, and plays. Enjoy watching on three screens simultaneously with one subscription from any device.\", \"en\": \"WATCH IT, the premier VOD platform in the region, has the biggest Arabic library in the MENA region, from original productions, to exclusives including series, programs, movies, and plays. Enjoy watching on three screens simultaneously with one subscription from any device.\"}', '{\"ar\": \"How to redeem WATCH IT card:\\\\n1- Enter the link: www.watchit.com  \\\\n2- Log in or sign up using your email and password.\\\\n3- Click on &apos;Do you have a Promo code?&apos;.\\\\n4- Enter the code (xxxx) without spaces.\\\\n5- Enjoy watching unlimited library of originals and exclusives titles.\\\\n\", \"en\": \"How to redeem WATCH IT card:\\\\n1- Enter the link: www.watchit.com  \\\\n2- Log in or sign up using your email and password.\\\\n3- Click on &apos;Do you have a Promo code?&apos;.\\\\n4- Enter the code (xxxx) without spaces.\\\\n5- Enjoy watching unlimited library of originals and exclusives titles.\\\\n\"}', '{\"ar\": \"1- promocodes valid for 6 months.\\\\n2- For terms and conditions please visit: https://www.watchit.com/#/terms-and-conditions\\\\n\", \"en\": \"1- promocodes valid for 6 months.\\\\n2- For terms and conditions please visit: https://www.watchit.com/#/terms-and-conditions\\\\n\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(464, '1773', 'like_card', '{\"ar\": \"iQIYI\", \"en\": \"iQIYI\"}', '{\"ar\": \"Become an iQIYI member to enjoy the best and latest Asian drama series - C-drama, K-drama, Thai-Drama and more to watch online. VIP privilege includes: Concurrent watching on multiple screens, enjoy ad-free viewing while watching shows, enjoy content with stream quality up to 4K.\", \"en\": \"Become an iQIYI member to enjoy the best and latest Asian drama series - C-drama, K-drama, Thai-Drama and more to watch online. VIP privilege includes: Concurrent watching on multiple screens, enjoy ad-free viewing while watching shows, enjoy content with stream quality up to 4K.\"}', '{\"ar\": \"1. Go to iQIYI VIP redeem page: https://www.iq.com/vip/codekey?H5=true \\\\n 2. Log in your account and enter the voucher code. \", \"en\": \"1. Go to iQIYI VIP redeem page: https://www.iq.com/vip/codekey?H5=true \\\\n 2. Log in your account and enter the voucher code. \"}', '{\"ar\": \" 1. Upon successful redemption, you will immediately receive the corresponding type and duration of iQIYI VIP membership, which will be ceased after the specified duration, and there will be no automatic renewal. Once redeemed, the voucher code cannot be refund or exchange. \\\\n2. Please redeem the code before expiration date. \\\\n3. If you have any question, please contact customer service contactus@qiyi.com\", \"en\": \" 1. Upon successful redemption, you will immediately receive the corresponding type and duration of iQIYI VIP membership, which will be ceased after the specified duration, and there will be no automatic renewal. Once redeemed, the voucher code cannot be refund or exchange. \\\\n2. Please redeem the code before expiration date. \\\\n3. If you have any question, please contact customer service contactus@qiyi.com\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(465, '1774', 'like_card', '{\"ar\": \"iQIYI - KSA\", \"en\": \"iQIYI - KSA\"}', '{\"ar\": \"Become an iQIYI member to enjoy the best and latest Asian drama series - C-drama, K-drama, Thai-Drama and more to watch online. VIP privilege includes: Concurrent watching on multiple screens, enjoy ad-free viewing while watching shows, enjoy content with stream quality up to 4K.\", \"en\": \"Become an iQIYI member to enjoy the best and latest Asian drama series - C-drama, K-drama, Thai-Drama and more to watch online. VIP privilege includes: Concurrent watching on multiple screens, enjoy ad-free viewing while watching shows, enjoy content with stream quality up to 4K.\"}', '{\"ar\": \"1. Go to iQIYI VIP redeem page: https://www.iq.com/vip/codekey?H5=true \\\\n2. Log in your account and enter the voucher code. \", \"en\": \"1. Go to iQIYI VIP redeem page: https://www.iq.com/vip/codekey?H5=true \\\\n2. Log in your account and enter the voucher code. \"}', '{\"ar\": \" 1. Upon successful redemption, you will immediately receive the corresponding type and duration of iQIYI VIP membership, which will be ceased after the specified duration, and there will be no automatic renewal. Once redeemed, the voucher code cannot be refund or exchange. \\\\n2. Please redeem the code before expiration date. \\\\n3. If you have any question, please contact customer service contactus@qiyi.com\", \"en\": \" 1. Upon successful redemption, you will immediately receive the corresponding type and duration of iQIYI VIP membership, which will be ceased after the specified duration, and there will be no automatic renewal. Once redeemed, the voucher code cannot be refund or exchange. \\\\n2. Please redeem the code before expiration date. \\\\n3. If you have any question, please contact customer service contactus@qiyi.com\"}', 464, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(466, '1775', 'like_card', '{\"ar\": \"iQIYI - UAE\", \"en\": \"iQIYI - UAE\"}', '{\"ar\": \"Become an iQIYI member to enjoy the best and latest Asian drama series - C-drama, K-drama, Thai-Drama and more to watch online. VIP privilege includes: Concurrent watching on multiple screens, enjoy ad-free viewing while watching shows, enjoy content with stream quality up to 4K.\", \"en\": \"Become an iQIYI member to enjoy the best and latest Asian drama series - C-drama, K-drama, Thai-Drama and more to watch online. VIP privilege includes: Concurrent watching on multiple screens, enjoy ad-free viewing while watching shows, enjoy content with stream quality up to 4K.\"}', '{\"ar\": \"1. Go to iQIYI VIP redeem page: https://www.iq.com/vip/codekey?H5=true \\\\n2. Log in your account and enter the voucher code. \", \"en\": \"1. Go to iQIYI VIP redeem page: https://www.iq.com/vip/codekey?H5=true \\\\n2. Log in your account and enter the voucher code. \"}', '{\"ar\": \" 1. Upon successful redemption, you will immediately receive the corresponding type and duration of iQIYI VIP membership, which will be ceased after the specified duration, and there will be no automatic renewal. Once redeemed, the voucher code cannot be refund or exchange. \\\\n2. Please redeem the code before expiration date. \\\\n3. If you have any question, please contact customer service contactus@qiyi.com  \", \"en\": \" 1. Upon successful redemption, you will immediately receive the corresponding type and duration of iQIYI VIP membership, which will be ceased after the specified duration, and there will be no automatic renewal. Once redeemed, the voucher code cannot be refund or exchange. \\\\n2. Please redeem the code before expiration date. \\\\n3. If you have any question, please contact customer service contactus@qiyi.com  \"}', 464, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
