INSERT INTO `digital_merchants` (`id`, `merchant_id`, `company_name`, `name`, `description`, `redeem_steps`, `terms`, `parent_id`, `last_synced_at`, `created_at`, `updated_at`) VALUES
(472, '1273', 'like_card', '{\"ar\": \"BluTV Üyelik - TR\", \"en\": \"BluTV Üyelik - TR\"}', '{\"ar\": \"BluTV is a media provider that gives you access to locally and internationally produced movies and TV series updated monthly, live TV broadcasts, sports and lifestyle content, and most importantly, locally produced movies and TV series available exclusively to members on BluTV, accessible via computer, mobile phone, tablet, and smart TV.With a membership, you can access all content without ads.\", \"en\": \"BluTV is a media provider that gives you access to locally and internationally produced movies and TV series updated monthly, live TV broadcasts, sports and lifestyle content, and most importantly, locally produced movies and TV series available exclusively to members on BluTV, accessible via computer, mobile phone, tablet, and smart TV.With a membership, you can access all content without ads.\"}', '{\"ar\": \"How to use BluTV cards:To use the BluTV membership coupon you purchase through LikeCard, follow these steps:1- Log in at https://www.blutv.com/. Then click on your profile icon in the top right corner.2- Enter the code you purchased from LikeCard in the “Use Coupon Code” section, then click “Add Coupon Code.”\", \"en\": \"How to use BluTV cards:To use the BluTV membership coupon you purchase through LikeCard, follow these steps:1- Log in at https://www.blutv.com/. Then click on your profile icon in the top right corner.2- Enter the code you purchased from LikeCard in the “Use Coupon Code” section, then click “Add Coupon Code.”\"}', '{\"ar\": \"1- You can activate a 1-month Blutv membership by entering the coupon code at blutv.com.tr/kupon.2- Only available in Turkey and Northern Cyprus.3- Products are delivered instantly as e-pins after the payment process is completed.4- In accordance with the relevant article of the Turkish Commercial Law, digital products cannot be returned.\", \"en\": \"1- You can activate a 1-month Blutv membership by entering the coupon code at blutv.com.tr/kupon.2- Only available in Turkey and Northern Cyprus.3- Products are delivered instantly as e-pins after the payment process is completed.4- In accordance with the relevant article of the Turkish Commercial Law, digital products cannot be returned.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(473, '1126', 'like_card', '{\"ar\": \"Twitch\", \"en\": \"Twitch\"}', '{\"ar\": \"Twitch is where millions of people come together live every day to chat, interact, and make their own entertainment together. Twitch gift cards are the perfect gift for anyone who watches Twitch.\", \"en\": \"Twitch is where millions of people come together live every day to chat, interact, and make their own entertainment together. Twitch gift cards are the perfect gift for anyone who watches Twitch.\"}', '{\"ar\": \"How to redeem Twitch cards:\\\\n1- Enter the link: https://www.twitch.tv/redeem\\\\n2- Enter the card code that you got from LikeCard.\\\\n3- Click on Redeem.\\\\n\", \"en\": \"How to redeem Twitch cards:\\\\n1- Enter the link: https://www.twitch.tv/redeem\\\\n2- Enter the card code that you got from LikeCard.\\\\n3- Click on Redeem.\\\\n\"}', '{\"ar\": \"1- This pass may only be redeemed on Twitch.tv, only by persons 13 years of age or older, and only for goods and services offered by Twitch or for goods sold on Twitch.tv or its apps.\\\\n2- This card cannot be returned, refunded, resold or redeemed for cash, except as required by applicable law.\\\\n3- This card cannot be used to purchase other gift cards. This card is non-refundable for non-US residents.\\\\n4- This card and the value behind this card is not expired. This card is non-reloadable.\\\\n5- There are no fees associated with this card.\\\\n6- Treat this gift card like cash. Twitch is not responsible for lost, stolen, damaged, damaged or misplaced cards, or cards used without your permission.\\\\n7- This card was issued by Twitch Interactive, Inc.. Please see additional terms and conditions, including instructions for redeeming this card, http://attwitch.tv/legal/giftcard For customer service, visit https://help.twitch.tv/s/\", \"en\": \"1- This pass may only be redeemed on Twitch.tv, only by persons 13 years of age or older, and only for goods and services offered by Twitch or for goods sold on Twitch.tv or its apps.\\\\n2- This card cannot be returned, refunded, resold or redeemed for cash, except as required by applicable law.\\\\n3- This card cannot be used to purchase other gift cards. This card is non-refundable for non-US residents.\\\\n4- This card and the value behind this card is not expired. This card is non-reloadable.\\\\n5- There are no fees associated with this card.\\\\n6- Treat this gift card like cash. Twitch is not responsible for lost, stolen, damaged, damaged or misplaced cards, or cards used without your permission.\\\\n7- This card was issued by Twitch Interactive, Inc.. Please see additional terms and conditions, including instructions for redeeming this card, http://attwitch.tv/legal/giftcard For customer service, visit https://help.twitch.tv/s/\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(474, '1263', 'like_card', '{\"ar\": \"XBOX - Turkish\", \"en\": \"XBOX - Turkish\"}', '{\"ar\": \"If you are a fan of Xbox One, and a fan of games, this offer is especially for you.There are three types of gamers, who use the computer, the owners of the PlayStation, and the third category is the Xbox lovers, because of its fast interface and distinctive features.Today we offer you XBOX - Turkish cards to enjoy all the benefits, new and exclusive games, a promium account that supports all additions and updates, and the latest game releases.For full content and a premium subscription, with a secure payment method to protect your account, Xbox cards are the perfect solution, with different prices and packages that meet your multiple needs.So what are you waiting for to get the latest games, features and updates on your Xbox?Recharge, and enjoy an unlimited world of fun and games.\\\"\", \"en\": \"If you are a fan of Xbox One, and a fan of games, this offer is especially for you.There are three types of gamers, who use the computer, the owners of the PlayStation, and the third category is the Xbox lovers, because of its fast interface and distinctive features.Today we offer you XBOX - Turkish cards to enjoy all the benefits, new and exclusive games, a promium account that supports all additions and updates, and the latest game releases.For full content and a premium subscription, with a secure payment method to protect your account, Xbox cards are the perfect solution, with different prices and packages that meet your multiple needs.So what are you waiting for to get the latest games, features and updates on your Xbox?Recharge, and enjoy an unlimited world of fun and games.\\\"\"}', '{\"ar\": \"How to recharge xbox :\\\\nRedeem a code on Xbox One, Xbox Series X and Xbox Series S:\\\\n1-Sign in to your Xbox console (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-From the Home screen, select and open the Store app. (If the Store app is not displayed, go to My games\\\\n& apps, select Apps, and select the Store app from there.)\\\\n3-In the Store app, move the cursor left or press the View button to open the side menu then select redeem.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code Using an Android or IOS mobile device:\\\\nGo to the link: https://redeem.microsoft.com.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code on Windows 10/11:\\\\n1-Sign in to your Windows device (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-Press the Start button, type store, then select Microsoft Store.\\\\n3-Select More … > Redeem a code.\\\\n4-Enter the 25-character code, and then follow the instructions.\", \"en\": \"How to recharge xbox :\\\\nRedeem a code on Xbox One, Xbox Series X and Xbox Series S:\\\\n1-Sign in to your Xbox console (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-From the Home screen, select and open the Store app. (If the Store app is not displayed, go to My games\\\\n& apps, select Apps, and select the Store app from there.)\\\\n3-In the Store app, move the cursor left or press the View button to open the side menu then select redeem.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code Using an Android or IOS mobile device:\\\\nGo to the link: https://redeem.microsoft.com.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code on Windows 10/11:\\\\n1-Sign in to your Windows device (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-Press the Start button, type store, then select Microsoft Store.\\\\n3-Select More … > Redeem a code.\\\\n4-Enter the 25-character code, and then follow the instructions.\"}', '{\"ar\": \"This product is for Turkish Store\", \"en\": \"This product is for Turkish Store\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(475, '146', 'like_card', '{\"ar\": \"XBOX - SAUDI\", \"en\": \"XBOX - SAUDI\"}', '{\"ar\": \"If you are a fan of Xbox One, and a fan of games, this offer is especially for you.\\\\nThere are three types of gamers, who use the computer, the owners of the PlayStation, and the third category is the Xbox lovers, because of its fast interface and distinctive features.\\\\nToday we offer you XBOX - SAUDI cards to enjoy all the benefits, new and exclusive games, a promium account that supports all additions and updates, and the latest game releases.\\\\nFor full content and a premium subscription, with a secure payment method to protect your account, Xbox cards are the perfect solution, with different prices and packages that meet your multiple needs.\\\\nSo what are you waiting for to get the latest games, features and updates on your Xbox?\\\\nRecharge, and enjoy an unlimited world of fun and games.\\\\n\", \"en\": \"If you are a fan of Xbox One, and a fan of games, this offer is especially for you.\\\\nThere are three types of gamers, who use the computer, the owners of the PlayStation, and the third category is the Xbox lovers, because of its fast interface and distinctive features.\\\\nToday we offer you XBOX - SAUDI cards to enjoy all the benefits, new and exclusive games, a promium account that supports all additions and updates, and the latest game releases.\\\\nFor full content and a premium subscription, with a secure payment method to protect your account, Xbox cards are the perfect solution, with different prices and packages that meet your multiple needs.\\\\nSo what are you waiting for to get the latest games, features and updates on your Xbox?\\\\nRecharge, and enjoy an unlimited world of fun and games.\\\\n\"}', '{\"ar\": \"How to recharge xbox :\\\\nRedeem a code on Xbox One, Xbox Series X and Xbox Series S:\\\\n1-Sign in to your Xbox console (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-From the Home screen, select and open the Store app. (If the Store app is not displayed, go to My games\\\\n& apps, select Apps, and select the Store app from there.)\\\\n3-In the Store app, move the cursor left or press the View button to open the side menu then select redeem.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code Using an Android or IOS mobile device:\\\\nGo to the link: https://redeem.microsoft.com.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code on Windows 10/11:\\\\n1-Sign in to your Windows device (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-Press the Start button, type store, then select Microsoft Store.\\\\n3-Select More … > Redeem a code.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\n\", \"en\": \"How to recharge xbox :\\\\nRedeem a code on Xbox One, Xbox Series X and Xbox Series S:\\\\n1-Sign in to your Xbox console (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-From the Home screen, select and open the Store app. (If the Store app is not displayed, go to My games\\\\n& apps, select Apps, and select the Store app from there.)\\\\n3-In the Store app, move the cursor left or press the View button to open the side menu then select redeem.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code Using an Android or IOS mobile device:\\\\nGo to the link: https://redeem.microsoft.com.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code on Windows 10/11:\\\\n1-Sign in to your Windows device (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-Press the Start button, type store, then select Microsoft Store.\\\\n3-Select More … > Redeem a code.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\n\"}', '{\"ar\": \"This product is for Saudi Store\", \"en\": \"This product is for Saudi Store\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(476, '63', 'like_card', '{\"ar\": \"XBOX - USA\", \"en\": \"XBOX - USA\"}', '{\"ar\": \"If you are a fan of Xbox One, and a fan of games, this offer is especially for you.There are three types of gamers, who use the computer, the owners of the PlayStation, and the third category is the Xbox lovers, because of its fast interface and distinctive features.Today we offer you XBOX - USA cards to enjoy all the benefits, new and exclusive games, a promium account that supports all additions and updates, and the latest game releases.For full content and a premium subscription, with a secure payment method to protect your account, Xbox cards are the perfect solution, with different prices and packages that meet your multiple needs.So what are you waiting for to get the latest games, features and updates on your Xbox?Recharge, and enjoy an unlimited world of fun and games.\\\\n\", \"en\": \"If you are a fan of Xbox One, and a fan of games, this offer is especially for you.There are three types of gamers, who use the computer, the owners of the PlayStation, and the third category is the Xbox lovers, because of its fast interface and distinctive features.Today we offer you XBOX - USA cards to enjoy all the benefits, new and exclusive games, a promium account that supports all additions and updates, and the latest game releases.For full content and a premium subscription, with a secure payment method to protect your account, Xbox cards are the perfect solution, with different prices and packages that meet your multiple needs.So what are you waiting for to get the latest games, features and updates on your Xbox?Recharge, and enjoy an unlimited world of fun and games.\\\\n\"}', '{\"ar\": \"How to recharge xbox card :\\\\nRedeem a code on Xbox One, Xbox Series X and Xbox Series S:\\\\n1-Sign in to your Xbox console (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-From the Home screen, select and open the Store app. (If the Store app is not displayed, go to My games\\\\n& apps, select Apps, and select the Store app from there.)\\\\n3-In the Store app, move the cursor left or press the View button to open the side menu then select redeem.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code Using an Android or IOS mobile device:\\\\nGo to the link: https://redeem.microsoft.com/\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code on Windows 10/11:\\\\n1-Sign in to your Windows device (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-Press the Start button, type store, then select Microsoft Store.\\\\n3-Select More … Redeem a code.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nATTENTION: This card is intended exclusively for American accounts, and therefore your account must be American and registered with a real American number and address so that you do not encounter any problem when trying to charge or use the card.\\\\n\", \"en\": \"How to recharge xbox card :\\\\nRedeem a code on Xbox One, Xbox Series X and Xbox Series S:\\\\n1-Sign in to your Xbox console (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-From the Home screen, select and open the Store app. (If the Store app is not displayed, go to My games\\\\n& apps, select Apps, and select the Store app from there.)\\\\n3-In the Store app, move the cursor left or press the View button to open the side menu then select redeem.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code Using an Android or IOS mobile device:\\\\nGo to the link: https://redeem.microsoft.com/\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nRedeem a code on Windows 10/11:\\\\n1-Sign in to your Windows device (make sure you’re signed in with the Microsoft account you want to redeem the code with).\\\\n2-Press the Start button, type store, then select Microsoft Store.\\\\n3-Select More … Redeem a code.\\\\n4-Enter the 25-character code, and then follow the instructions.\\\\nATTENTION: This card is intended exclusively for American accounts, and therefore your account must be American and registered with a real American number and address so that you do not encounter any problem when trying to charge or use the card.\\\\n\"}', '{\"ar\": \"- This product is for American Store\", \"en\": \"- This product is for American Store\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
