(495, '1449', 'like_card', '{\"ar\": \"LikeCard - TR\", \"en\": \"LikeCard - TR\"}', '{\"ar\": \"A digital card designed to help you effortlessly recharge your balance on the LikeCard app. You can also share it as a thoughtful gift with family and friends, giving them the convenience of easily choosing their favorite card directly from the app.\", \"en\": \"A digital card designed to help you effortlessly recharge your balance on the LikeCard app. You can also share it as a thoughtful gift with family and friends, giving them the convenience of easily choosing their favorite card directly from the app.\"}', '{\"ar\": \"How to redeem LikeCard cards:\\\\n1- Open the LikeCard app and log in to your account.2- From the bottom menu, select  Account  .3- Under your LikeCard balance, tap Recharge.4- In the “Recharge Card Balance” section, choose Redeem Code.5- Enter your unique gift card code and press Redeem Code to complete the process.\", \"en\": \"How to redeem LikeCard cards:\\\\n1- Open the LikeCard app and log in to your account.2- From the bottom menu, select  Account  .3- Under your LikeCard balance, tap Recharge.4- In the “Recharge Card Balance” section, choose Redeem Code.5- Enter your unique gift card code and press Redeem Code to complete the process.\"}', '{\"ar\": \"1- This card is valid for 12 months from the date of purchase.2- The currency of the card must be matched to the currency of your store in LikeCard in order to be able to use the product.\", \"en\": \"1- This card is valid for 12 months from the date of purchase.2- The currency of the card must be matched to the currency of your store in LikeCard in order to be able to use the product.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(496, '1770', 'like_card', '{\"ar\": \"Sparky\'s\", \"en\": \"Sparky\'s\"}', '{\"ar\": \" Looking for the perfect gift? Sparky&apos;s gift card is a gift of unforgettable memories, and the first and most famous amusement park chain in the Middle East. Surprise your loved ones wherever they are with a Sparky&apos;s card and let them experience moments full of excitement, fun, and adrenaline! Whether it&apos;s a birthday, a special occasion, or simply to bring happiness to their hearts, the Sparky&apos;s gift card is the perfect choice. It&apos;s easy to buy and use, ensuring you create lasting memories. Give the gift of adventure and joy, because the best gifts are not just thingsرthey are experiences that stay in the memory forever!\", \"en\": \" Looking for the perfect gift? Sparky&apos;s gift card is a gift of unforgettable memories, and the first and most famous amusement park chain in the Middle East. Surprise your loved ones wherever they are with a Sparky&apos;s card and let them experience moments full of excitement, fun, and adrenaline! Whether it&apos;s a birthday, a special occasion, or simply to bring happiness to their hearts, the Sparky&apos;s gift card is the perfect choice. It&apos;s easy to buy and use, ensuring you create lasting memories. Give the gift of adventure and joy, because the best gifts are not just thingsرthey are experiences that stay in the memory forever!\"}', '{\"ar\": \"- Visit the location and ask the cashier to redeem the voucher.\", \"en\": \"- Visit the location and ask the cashier to redeem the voucher.\"}', '{\"ar\": \" 1.The company or Sparky&apos;s are not responsible in case your card was lost, stolen, or damaged.2.The card balance can be used for group rides, video games and kiddy rides only.3.The card balance is valid for 6 months from the date of branch collection.4.Customers can know their card balance by scanning the QR barcode on the back of the card.5.The card balance is non-refundable and cannot be exchanged for cash.6.Customers can use their cards in any Sparky’s centers linked on the same network, and the company is not responsible for any temporary service interruption due to any problems out of the company&apos;s control.7.Customers must adhere to the riding instructions and safety requirements of each game.8.Sparky&apos;s and BAAN Holding Group reserve the right to modify any of the terms and conditions at any time without prior notice.9.The cards are not valid for resale or promotion on websites not contracted by BAAN Holding Group.10.Upon purchasing the card through the website, the customer receives a virtual card number on their registered number and presents it at any Sparky&apos;s branch to collect their card free of charge\", \"en\": \" 1.The company or Sparky&apos;s are not responsible in case your card was lost, stolen, or damaged.2.The card balance can be used for group rides, video games and kiddy rides only.3.The card balance is valid for 6 months from the date of branch collection.4.Customers can know their card balance by scanning the QR barcode on the back of the card.5.The card balance is non-refundable and cannot be exchanged for cash.6.Customers can use their cards in any Sparky’s centers linked on the same network, and the company is not responsible for any temporary service interruption due to any problems out of the company&apos;s control.7.Customers must adhere to the riding instructions and safety requirements of each game.8.Sparky&apos;s and BAAN Holding Group reserve the right to modify any of the terms and conditions at any time without prior notice.9.The cards are not valid for resale or promotion on websites not contracted by BAAN Holding Group.10.Upon purchasing the card through the website, the customer receives a virtual card number on their registered number and presents it at any Sparky&apos;s branch to collect their card free of charge\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(497, '143', 'like_card', '{\"ar\": \"MRSOOL CARDS\", \"en\": \"MRSOOL CARDS\"}', '{\"ar\": \"Use the Marsool card to charge your account with the Marsool application and enjoy a unique and fast experience in delivering orders from any mall.\\\\n\", \"en\": \"Use the Marsool card to charge your account with the Marsool application and enjoy a unique and fast experience in delivering orders from any mall.\\\\n\"}', '{\"ar\": \"How to redeem MARSOOL cards:\\\\n1- Log in to the marsool application.\\\\n2- Enter your account information.\\\\n3- From the Coupons tab, click on Add Coupon.\\\\n4- Enter the code that you got.\\\\n5- Click Verify to charge your account.\", \"en\": \"How to redeem MARSOOL cards:\\\\n1- Log in to the marsool application.\\\\n2- Enter your account information.\\\\n3- From the Coupons tab, click on Add Coupon.\\\\n4- Enter the code that you got.\\\\n5- Click Verify to charge your account.\"}', '{\"ar\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\", \"en\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(498, '1988', 'like_card', '{\"ar\": \"Jahez Prime\", \"en\": \"Jahez Prime\"}', '{\"ar\": \"An exclusive service available only through the Jahez app, offering free delivery from over 10,000 restaurants across Saudi Arabia. Designed to provide frequent users with comfort and efficiency, it transforms food delivery into an exceptional experience of speed, convenience, and joy. Jahez Prime is more than just a meal—it’s a thoughtful gift that delivers happiness to your loved ones with every order.\", \"en\": \"An exclusive service available only through the Jahez app, offering free delivery from over 10,000 restaurants across Saudi Arabia. Designed to provide frequent users with comfort and efficiency, it transforms food delivery into an exceptional experience of speed, convenience, and joy. Jahez Prime is more than just a meal—it’s a thoughtful gift that delivers happiness to your loved ones with every order.\"}', '{\"ar\": \"1- If you don’t have an active account, download the Jahez appDownload the app from Google Play: https://play.google.com/store/apps/details?id=net.jahez&hl=enDownload the app from App Store:https://apps.apple.com/sa/app/jahez/id1137352156Download the app from AppGalleryhttps://bit.ly/4oQRWRW2- Register and log in to start using the app.3- Open the Jahez app.4- Go to your profile and select “Prime.”5- Tap on “Redeem Code.”6- Enter the provided voucher code.\", \"en\": \"1- If you don’t have an active account, download the Jahez appDownload the app from Google Play: https://play.google.com/store/apps/details?id=net.jahez&hl=enDownload the app from App Store:https://apps.apple.com/sa/app/jahez/id1137352156Download the app from AppGalleryhttps://bit.ly/4oQRWRW2- Register and log in to start using the app.3- Open the Jahez app.4- Go to your profile and select “Prime.”5- Tap on “Redeem Code.”6- Enter the provided voucher code.\"}', '{\"ar\": \"1- The subscription will be activated based on the duration specified in the code.2- Vouchers are valid only for the specified duration (1, 3, 6, or 12 months).3- Prime benefits apply only to eligible restaurants as indicated in the app.4- The Voucher is valid for one-time use only.5- The card does not include VAT. - To contact customer service 800124124(Activation of Jahez Prime card is possible only for Saudi numbers.)\", \"en\": \"1- The subscription will be activated based on the duration specified in the code.2- Vouchers are valid only for the specified duration (1, 3, 6, or 12 months).3- Prime benefits apply only to eligible restaurants as indicated in the app.4- The Voucher is valid for one-time use only.5- The card does not include VAT. - To contact customer service 800124124(Activation of Jahez Prime card is possible only for Saudi numbers.)\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(499, '1749', 'like_card', '{\"ar\": \"Uber Eats\", \"en\": \"Uber Eats\"}', '{\"ar\": \"Get the food you want delivered fast and fresh.\", \"en\": \"Get the food you want delivered fast and fresh.\"}', '{\"ar\": \"To redeem this gift card:  Go to the Wallet Section in the Uber Eats app Tap Add Payment Method and select Gift Card  Enter Gift Code\", \"en\": \"To redeem this gift card:  Go to the Wallet Section in the Uber Eats app Tap Add Payment Method and select Gift Card  Enter Gift Code\"}', '{\"ar\": \" By using this gift card, you accept the following terms and conditions: This card is redeemable via the Uber or Uber Eats app within the U.S. in cities where Uber or Uber Eats is available. Funds do not expire. The card is non-reloadable and, except where required by law, cannot be redeemed for cash, refunded, or returned. You may be required to add a secondary payment method to use this gift card with the Uber or Uber Eats app. The card is not redeemable outside the U.S. Issuer is not responsible for lost or stolen cards, or unauthorized use. Depending on the state of purchase, this card is issued by Bancorp Card Services, Inc. or The Bancorp Bank. For full terms and conditions and customer service, visit uber.com/legal/gift.\", \"en\": \" By using this gift card, you accept the following terms and conditions: This card is redeemable via the Uber or Uber Eats app within the U.S. in cities where Uber or Uber Eats is available. Funds do not expire. The card is non-reloadable and, except where required by law, cannot be redeemed for cash, refunded, or returned. You may be required to add a secondary payment method to use this gift card with the Uber or Uber Eats app. The card is not redeemable outside the U.S. Issuer is not responsible for lost or stolen cards, or unauthorized use. Depending on the state of purchase, this card is issued by Bancorp Card Services, Inc. or The Bancorp Bank. For full terms and conditions and customer service, visit uber.com/legal/gift.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(500, '933', 'like_card', '{\"ar\": \"Morni\", \"en\": \"Morni\"}', '{\"ar\": \"Morni is the leading platform for mobility solutions in the Kingdom of Saudi Arabia providing towing and roadside assistance services for both on-demand clients and Morni membership holders through our Morni smartphone applications on Android and iPhone.\\\\n\", \"en\": \"Morni is the leading platform for mobility solutions in the Kingdom of Saudi Arabia providing towing and roadside assistance services for both on-demand clients and Morni membership holders through our Morni smartphone applications on Android and iPhone.\\\\n\"}', '{\"ar\": \"How to redeem Morni cards:\\\\n1- Click on Buy a new membership.\\\\n2- Agree to the terms and conditions.\\\\n3- Enter the card code that you got.\\\\n4- Click on Send.\\\\n5- Press OK.\\\\n\", \"en\": \"How to redeem Morni cards:\\\\n1- Click on Buy a new membership.\\\\n2- Agree to the terms and conditions.\\\\n3- Enter the card code that you got.\\\\n4- Click on Send.\\\\n5- Press OK.\\\\n\"}', '{\"ar\": \"- To view the terms and conditions, please visit: https://www.morniksa.com/terms_conditions?locale=en\\\\n\", \"en\": \"- To view the terms and conditions, please visit: https://www.morniksa.com/terms_conditions?locale=en\\\\n\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(501, '1305', 'like_card', '{\"ar\": \"Activitygift\", \"en\": \"Activitygift\"}', '{\"ar\": \"Activitygift cards are a perfect gift for people who love adventure and exciting activities. You can redeem it for over 50,000 activity options in over 680 cities and over 160 countries. Give them the freedom to decide what to do and where to enjoy activities around the world.\", \"en\": \"Activitygift cards are a perfect gift for people who love adventure and exciting activities. You can redeem it for over 50,000 activity options in over 680 cities and over 160 countries. Give them the freedom to decide what to do and where to enjoy activities around the world.\"}', '{\"ar\": \"How to redeem Activitygift card:\\\\n1- Enter the link: Activitygift.com\\\\n2- click on &apos;Redeem&apos;.\\\\n3- Select any activity from 50,000+ options.\\\\n4- Enter your Activitygift value code on the payment page and Enjoy your trip!\\\\n\", \"en\": \"How to redeem Activitygift card:\\\\n1- Enter the link: Activitygift.com\\\\n2- click on &apos;Redeem&apos;.\\\\n3- Select any activity from 50,000+ options.\\\\n4- Enter your Activitygift value code on the payment page and Enjoy your trip!\\\\n\"}', '{\"ar\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\", \"en\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(502, '1304', 'like_card', '{\"ar\": \"Hotelgift\", \"en\": \"Hotelgift\"}', '{\"ar\": \"Hotelgift cards are a wonderful gift for any occasion, as they allow the recipient to enjoy a luxurious stay experience at any hotel among more than 550,000 hotels and more than 140 hotel chains around the world. Hotelgift cards are an ideal way to enjoy a wonderful holiday or to experience moments of relaxation and entertainment in a distinguished hotel.\", \"en\": \"Hotelgift cards are a wonderful gift for any occasion, as they allow the recipient to enjoy a luxurious stay experience at any hotel among more than 550,000 hotels and more than 140 hotel chains around the world. Hotelgift cards are an ideal way to enjoy a wonderful holiday or to experience moments of relaxation and entertainment in a distinguished hotel.\"}', '{\"ar\": \" How to redeem Hotelgift card:1- Enter the link: Hotelgift.com2- click on &apos;Redeem.3- Select one of over 750,000 hotels.4- Enter your Hotelgift value code on the payment page and Enjoy your hotel!\", \"en\": \" How to redeem Hotelgift card:1- Enter the link: Hotelgift.com2- click on &apos;Redeem.3- Select one of over 750,000 hotels.4- Enter your Hotelgift value code on the payment page and Enjoy your hotel!\"}', '{\"ar\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\", \"en\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54');
