(503, '1303', 'like_card', '{\"ar\": \"Flightgift\", \"en\": \"Flightgift\"}', '{\"ar\": \"Flightgift cards The first choice when traveling, giving people the freedom of choice and flexibility to plan their trips. The card can be used to purchase airline tickets from hundreds of destinations around the world, providing an easy and exciting travel experience. A great gift for family and friends who love travel and adventure.\", \"en\": \"Flightgift cards The first choice when traveling, giving people the freedom of choice and flexibility to plan their trips. The card can be used to purchase airline tickets from hundreds of destinations around the world, providing an easy and exciting travel experience. A great gift for family and friends who love travel and adventure.\"}', '{\"ar\": \"How to redeem Flightgift card:\\\\n1- Enter the link: flightgift.com\\\\n2- click on &apos;Redeem&apos;.\\\\n3- Select any flight of 400+ airlines.\\\\n4- Enter your Flightgift value code on the payment page and Enjoy your trip!\\\\n\", \"en\": \"How to redeem Flightgift card:\\\\n1- Enter the link: flightgift.com\\\\n2- click on &apos;Redeem&apos;.\\\\n3- Select any flight of 400+ airlines.\\\\n4- Enter your Flightgift value code on the payment page and Enjoy your trip!\\\\n\"}', '{\"ar\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\", \"en\": \"- This gift card is non-refundable and cannot be exchanged for cash.- This gift card cannot be reloaded.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(504, '1767', 'like_card', '{\"ar\": \"Microsoft® Windows 11\", \"en\": \"Microsoft® Windows 11\"}', '{\"ar\": \"Windows 11 was designed to provide powerful security and a great user experience across a wide range of devices and settings.And a wide variety of devices and configurations.\", \"en\": \"Windows 11 was designed to provide powerful security and a great user experience across a wide range of devices and settings.And a wide variety of devices and configurations.\"}', '{\"ar\": \"On your Windows 11 PC:1. Type activation in the search bar and click on itActivation Settings.2. Click Change Product Key and enter the character code printed on your receipt.3. Click Next and then click Start.support.microsoft.com/windows \", \"en\": \"On your Windows 11 PC:1. Type activation in the search bar and click on itActivation Settings.2. Click Change Product Key and enter the character code printed on your receipt.3. Click Next and then click Start.support.microsoft.com/windows \"}', '{\"ar\": \"- For assistance, visit: www.microsoft.com/en-us/legal/terms-of-use\", \"en\": \"- For assistance, visit: www.microsoft.com/en-us/legal/terms-of-use\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(505, '1765', 'like_card', '{\"ar\": \"360 Moms\", \"en\": \"360 Moms\"}', '{\"ar\": \" About the AI Parents Advisor:Are you a parent with questions? We&apos;ve got answers!  Chat with AI Parents Advisor—your smart, friendly assistant for instant, science-backed tips on kids&apos; and women&apos;s health & well-being. Let’s make parenting easier together!\", \"en\": \" About the AI Parents Advisor:Are you a parent with questions? We&apos;ve got answers!  Chat with AI Parents Advisor—your smart, friendly assistant for instant, science-backed tips on kids&apos; and women&apos;s health & well-being. Let’s make parenting easier together!\"}', '{\"ar\": \"1-Go to this page   https://www.360moms.net2-Choose the plan that suits you: monthly or yearly.3-Click register to create an account4-Add your voucher code into the box allocated.5-Complete payment.Enjoy your subscription!\", \"en\": \"1-Go to this page   https://www.360moms.net2-Choose the plan that suits you: monthly or yearly.3-Click register to create an account4-Add your voucher code into the box allocated.5-Complete payment.Enjoy your subscription!\"}', '{\"ar\": \"- You can only use the e-voucher / gift card for one time..\", \"en\": \"- You can only use the e-voucher / gift card for one time..\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(506, '3055', 'like_card', '{\"ar\": \"360 Moms KSA\", \"en\": \"360 Moms KSA\"}', '{\"ar\": \" About the AI Parents Advisor:Are you a parent with questions? We&apos;ve got answers!  Chat with AI Parents Advisor—your smart, friendly assistant for instant, science-backed tips on kids&apos; and women&apos;s health & well-being. Let’s make parenting easier together!\", \"en\": \" About the AI Parents Advisor:Are you a parent with questions? We&apos;ve got answers!  Chat with AI Parents Advisor—your smart, friendly assistant for instant, science-backed tips on kids&apos; and women&apos;s health & well-being. Let’s make parenting easier together!\"}', '{\"ar\": \"1-Go to this page   https://www.360moms.net2-Choose the plan that suits you: monthly or yearly.3-Click register to create an account4-Add your voucher code into the box allocated.5-Complete payment.Enjoy your subscription!\", \"en\": \"1-Go to this page   https://www.360moms.net2-Choose the plan that suits you: monthly or yearly.3-Click register to create an account4-Add your voucher code into the box allocated.5-Complete payment.Enjoy your subscription!\"}', '{\"ar\": \"- You can only use the e-voucher / gift card for one time..\", \"en\": \"- You can only use the e-voucher / gift card for one time..\"}', 505, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(507, '497', 'like_card', '{\"ar\": \"Microsoft Office cards\", \"en\": \"Microsoft Office cards\"}', '{\"ar\": \"Microsoft Office 2019 for students and families who want to create great content in a fun and easy way including Word, PowerPoint and Excel. Now!! by purchasing a one-time Microsoft Office card, you can get the latest versions of Office programs and access any of the latest features and tools as soon as they are released, and install it on a single computer or on your Mac. Microsoft Office 365 cards for family and business are your ideal and secure way to save your files and provide them a technical support.\\\\n\", \"en\": \"Microsoft Office 2019 for students and families who want to create great content in a fun and easy way including Word, PowerPoint and Excel. Now!! by purchasing a one-time Microsoft Office card, you can get the latest versions of Office programs and access any of the latest features and tools as soon as they are released, and install it on a single computer or on your Mac. Microsoft Office 365 cards for family and business are your ideal and secure way to save your files and provide them a technical support.\\\\n\"}', '{\"ar\": \"How to redeem Microsoft office Cards:\\\\n1- Visit Microsoft Official redemption center [ https://redeem.microsoft.com/#/ ]\\\\n2- Log into your account or create new one.\\\\n3- Enter your code which consists of 25 characters.\\\\n4- Click on Next.\\\\n5- Congrats! Your subscription will be activated directly, and the full amount will be added to your Microsoft account.\\\\n\", \"en\": \"How to redeem Microsoft office Cards:\\\\n1- Visit Microsoft Official redemption center [ https://redeem.microsoft.com/#/ ]\\\\n2- Log into your account or create new one.\\\\n3- Enter your code which consists of 25 characters.\\\\n4- Click on Next.\\\\n5- Congrats! Your subscription will be activated directly, and the full amount will be added to your Microsoft account.\\\\n\"}', '{\"ar\": \"This  gift card is non-refundable and cannot be exchanged for cash.\\\\n    This gift card cannot be reloaded.\", \"en\": \"This  gift card is non-refundable and cannot be exchanged for cash.\\\\n    This gift card cannot be reloaded.\"}', NULL, '2026-04-09 08:41:54', '2026-04-06 11:06:11', '2026-04-09 08:41:54'),
(508, '3080', 'like_card', '{\"ar\": \"MUSE - TOM FORD\", \"en\": \"MUSE - TOM FORD\"}', NULL, NULL, NULL, NULL, '2026-04-09 08:41:54', '2026-04-09 08:41:54', '2026-04-09 08:41:54'),
(509, '342', 'like_card', '{\"ar\": \"Mobile Legends Cards\", \"en\": \"Mobile Legends Cards\"}', '{\"ar\": \"If you seek to excel in Mobile Legends and become a legend, you must unlock the strongest characters, and have great resources.\\\\nNow with Mobile Legends cards you can.\\\\nwe provide you with Mobile Legends Cards prepaid cards to charge your account on Mobile Legends game to enable you to buy everything you need from powerful characters, advanced weapons and costumes that match your personality.\\\\nIt is available with different offers and prices to meet the needs of all players.\\\\nJust pay in completely safe ways and get your card to enjoy the game without limits.\\\\n\", \"en\": \"If you seek to excel in Mobile Legends and become a legend, you must unlock the strongest characters, and have great resources.\\\\nNow with Mobile Legends cards you can.\\\\nwe provide you with Mobile Legends Cards prepaid cards to charge your account on Mobile Legends game to enable you to buy everything you need from powerful characters, advanced weapons and costumes that match your personality.\\\\nIt is available with different offers and prices to meet the needs of all players.\\\\nJust pay in completely safe ways and get your card to enjoy the game without limits.\\\\n\"}', '{\"ar\": \"How to redeem Mobile Legends cards:\\\\n1- Log onto the website of MLBB: https://m.mobilelegends.com/en/\\\\n2- Find the ‘Redeem’ button on the right corner and click it.\\\\n3- Enter your Game ID and click the ‘Send’ button. Then you will receive a verification code in your in-game mailbox.\\\\n4- Enter the code you receive from the in-game mailbox.\\\\n5- Finally, enter the 17 digits redemption code and click ‘Redeem’. The item will automatically be sent into your in-game mailbox.\\\\n\", \"en\": \"How to redeem Mobile Legends cards:\\\\n1- Log onto the website of MLBB: https://m.mobilelegends.com/en/\\\\n2- Find the ‘Redeem’ button on the right corner and click it.\\\\n3- Enter your Game ID and click the ‘Send’ button. Then you will receive a verification code in your in-game mailbox.\\\\n4- Enter the code you receive from the in-game mailbox.\\\\n5- Finally, enter the 17 digits redemption code and click ‘Redeem’. The item will automatically be sent into your in-game mailbox.\\\\n\"}', '{\"ar\": \"- This product is valid for use in all countries\\\\n\", \"en\": \"- This product is valid for use in all countries\\\\n\"}', NULL, '2026-04-09 08:41:54', '2026-04-09 08:41:54', '2026-04-09 08:41:54'),
