(998, '99654', 'one_card', 307, NULL, NULL, '{\"ar\": \"بطاقة إعادة شحن سوا بقيمة 20 ريال\", \"en\": \"Sawa Recharge Card SR 20\"}', 'onecard-one_card-99654', NULL, '{\"ar\": \"<li>1- يمكن شحن البطاقة بعد شرائها عن طريق الضغط على الرابط التالي:<a href=\\\"http://connect.mobily.com.sa/html/\\\">http://connect.mobily.com.sa</a> </li>\\r\\n\\r\\n<li>2- أو بالاتصال على: *1400*رقم بطاقة الشحن# .</li>\\r\\n<br><br>\\r\\n</ul>\\r\\n</ul>\\r\\n</br>\\r\\n<ul class=\\\"text\\\">\\r\\n<li>يمكنك أيضا مشاهدة و شراء هذه البطاقات:</li>\\r\\n<li> <a href=\\\"https://www.bitaqaty.com/sa-ar/merchant/52/648104/quick-net-cards---stc\\\">بطاقات كويك نت </a> </li>\\r\\n<li> <a href=\\\"https://www.bitaqaty.com/sa-ar/merchant/52/115402/sawa-cards\\\">بطاقات شحن سوا </a> </li>\\r\\n<li> <a href=\\\"https://www.bitaqaty.com/sa-ar/merchant/52/310619/zain---saudi-arabia\\\">بطاقات شحن زين السعوديه </a> </li>\\r\\n</ul>\\r\\n</br>\", \"en\": \"<ul><li>1- Vouchers can be recharged by clicking on: <a href=\\\"http://connect.mobily.com.sa/html/\\\">http://connect.mobily.com.sa</a> </li>\\r\\n<li>2- Or by dialing *1400*voucher Number# </li>\\r\\n</ul>\"}', 'digital-products/onecard-99654-g3ZGz2wn.jpg', 5.39, 5.39, 'USD', 1, 1, 0, 0, 1, '2026-03-24 15:47:09', '2026-03-24 15:47:09'),
(999, '3718', 'one_card', 308, NULL, NULL, '{\"ar\": \"بطاقة بلايستيشن ستور سعودي 20 دولار SM\", \"en\": \"PlayStation KSA Store $20 SM\"}', 'onecard-one_card-3718', NULL, '{\"ar\": \"<ul class=\\\"text\\\">\\r\\n<li>1- اختر الفئة التي تريد شراؤها، ثم اضغط على \\\"اشترى الآن\\\".</li>\\r\\n<li>2- احتفظ ببيانات المنتج (الكود).</li>\\r\\n<li>3- قم بزيارة موقع بلايستيشن نتوورك ستور.</li>\\r\\n<li>4- سجل دخولك على حسابك الخاص.</li>\\r\\n<li>5-  اضغط على \\\"Redeem Prepaid Card\\\".</li>\\r\\n<li>6- ادخل بيانات المنتج \\\"الكود.</li>\\r\\n</ul>\\r\\n</ul>\\r\\n</br>\\r\\n<ul class=\\\"text\\\">\\r\\n<li>يمكنك أيضا مشاهدة و شراء هذه البطاقات:</li>\\r\\n<li> <a href=\\\"https://www.bitaqaty.com/sa-ar/merchant/40/1702083/playstation-store-usa\\\">بطاقات بلايستيشن ستور أمريكي </a> </li>\\r\\n<li> <a href=\\\"https://www.bitaqaty.com/sa-ar/merchant/40/1702078/playstation-store-uk\\\">بطاقات بلايستيشن ستور بريطاني </a> </li>\\r\\n<li> <a href=\\\"https://www.bitaqaty.com/sa-ar/merchant/40/1743256/playstation-store-lebanon\\\">بطاقات بلايستيشن ستور لبناني </a> </li>\\r\\n</ul>\\r\\n</br>\", \"en\": \"<ul class=\\\"text\\\">\\r\\n<li>1- Choose the Card (Voucher) you want to buy, then click \\\"Buy Now\\\".</li>\\r\\n<li>2- Keep the Product code (Voucher).</li>\\r\\n<li>3- Visit PlayStation Network site.</li>\\r\\n<li>4- Login into your account.</li>\\r\\n<li>5-Click \\\"Redeem Prepaid Card\\\".</li>\\r\\n<li>6- Type your card code.</li>\\r\\n\\r\\n\\r\\n</ul>\"}', 'digital-products/onecard-3718-pj8HJojK.jpg', 20.74, 20.74, 'USD', 1, 1, 0, 0, 1, '2026-03-24 15:47:09', '2026-03-24 15:47:09');
