(1003, '3722', 'one_card', 310, NULL, NULL, '{\"ar\": \"zain Card 1\", \"en\": \"zain Card 1\"}', 'onecard-one_card-3722', NULL, '{\"ar\": \"\", \"en\": \"\"}', 'digital-products/onecard-3722-iRp6PeQl.jpg', 68.00, 68.00, 'USD', 1, 1, 0, 0, 1, '2026-03-24 15:47:09', '2026-03-24 15:47:09'),
(1004, '3725', 'one_card', 311, NULL, NULL, '{\"ar\": \"بطاقة أوبر للسائق - 10 ريال\", \"en\": \"Uber Driver Voucher - SAR10\"}', 'onecard-one_card-3725', NULL, '{\"ar\": \"<ul class=\\\"text\\\">\\r\\n<li>الطريقة اﻻولى / </li>\\r\\n<li>1-قم بتسجيل دخولك إلى تطبيق أوبر درايفر. </li>\\r\\n<li>2- اختر أيقونة الحساب، ومن ثم اختر الدفع. </li>\\r\\n<li>3- اختر قسيمة الهدايا كوسيلة للدفع. </li>\\r\\n<li>4- أدخل رمز القسيمة. </li>\\r\\n<li>5- مبروك! سوف يتم خصم المبلغ المستحق. </li> </ul>\\r\\n\\r\\n<ul class=\\\"text\\\">\\r\\n<li>/ الطريقة الثانية </li>\\r\\n<li>1-قم بتسجيل الدخول إلى حسابك في أوبر درايفر. </li>\\r\\n<li>2- من أعلى الشاشة اضغط على القائمة المنسدلة، اختر المحفظة. </li>\\r\\n<li>3- اختر قسيمة الهدايا كوسيلة للدفع. </li>\\r\\n<li>4- أدخل رمز القسيمة. </li>\\r\\n<li>5- مبروك! سوف يتم خصم المبلغ المستحق. </li> </ul>\", \"en\": \"<ul class=\\\"text\\\">\\r\\n<li>First Way \\\\</li>\\r\\n<li>1- Log into your Uber Driver account. </li>\\r\\n<li>2- Choose Profile icon, then choose Payment. </li>\\r\\n<li>3- Choose Voucher as a payment. </li>\\r\\n<li>4- Enter your voucher number. </li>\\r\\n<li>5- Congrats! The amount will be settled. </li> </ul> \\r\\n\\r\\n<ul class=\\\"text\\\">\\r\\n<li>Second Way \\\\</li>\\r\\n<li>1- Log into your Uber Driver account. </li>\\r\\n<li>2- Click on the drop list, then choose Wallet. </li>\\r\\n<li>3- Choose Voucher as a payment. </li>\\r\\n<li>4- Enter your voucher number. </li>\\r\\n<li>5- Congrats! The amount will be settled. </li> </ul> \"}', 'digital-products/onecard-3725-mLFCv2Gi.jpg', 3.50, 3.50, 'USD', 1, 1, 0, 0, 1, '2026-03-24 15:47:09', '2026-03-24 15:47:09'),
