INSERT INTO `faqs` (`id`, `question`, `answer`, `order`, `is_active`, `created_at`, `updated_at`) VALUES
(1, '{\"ar\": \"كيف يمكنني تتبع طلبي؟\", \"en\": \"How can I track my order?\"}', '{\"ar\": \"بمجرد شحن طلبك، ستصلك رسالة تحتوي على رابط التتبع عبر البريد الإلكتروني أو رسالة نصية. كما يمكنك تتبع الطلب من خلال حسابك في قسم \\\"طلباتي\\\".\", \"en\": \"Once your order is shipped, you will receive a tracking link via email and SMS. You can also track it from your account dashboard under “My Orders”.\"}', 4, 1, '2026-02-15 10:17:44', '2026-05-06 17:27:42'),
(2, '{\"ar\": \"كم تستغرق مدة الشحن؟\", \"en\": \"How long does shipping take?\"}', '{\"ar\": \"الشحن العادي يستغرق من 3 إلى 5 أيام عمل. الشحن السريع يستغرق من 1 إلى يومين عمل حسب موقعك.\", \"en\": \"Standard shipping takes 3–5 business days. Express shipping takes 1–2 business days depending on your location.\"}', 2, 1, '2026-02-15 10:37:07', '2026-02-15 10:37:07'),
(3, '{\"ar\": \"ما هي سياسة الإرجاع؟\", \"en\": \"What is your return policy?\"}', '{\"ar\": \"يمكنك إرجاع المنتج خلال 14 يومًا من تاريخ الاستلام بشرط أن يكون غير مستخدم وفي عبوته الأصلية.\", \"en\": \"You can return products within 14 days of delivery, provided they are unused and in original packaging.\"}', 3, 1, '2026-02-15 10:37:41', '2026-05-06 17:27:22');
